import React from "react";
import { CreditCardIcon } from "@heroicons/react/24/outline";

const CardsPage = () => {
  return (
    <div className="space-y-6">
      <div>
        <h1 className="page-title">Payment Cards</h1>
        <p className="page-subtitle">
          Monitor linked payment cards and manage card security.
        </p>
      </div>

      <div className="card">
        <div className="card-body flex flex-col items-center py-16 text-center">
          <div className="h-14 w-14 rounded-2xl bg-violet-50 flex items-center justify-center mb-4">
            <CreditCardIcon className="h-7 w-7 text-violet-600" />
          </div>
          <h3 className="text-sm font-semibold text-slate-900">
            Card Management
          </h3>
          <p className="text-xs text-slate-500 mt-1.5 max-w-xs">
            Linked card registry, freeze/unfreeze controls, and security alerts
            — coming soon.
          </p>
        </div>
      </div>
    </div>
  );
};

export default CardsPage;
