import React from "react";
import { BookOpenIcon } from "@heroicons/react/24/outline";

const EducationPage = () => {
  return (
    <div className="space-y-6">
      <div>
        <h1 className="page-title">Education Content</h1>
        <p className="page-subtitle">
          Manage educational content, categories, and user learning progress.
        </p>
      </div>

      <div className="card">
        <div className="card-body flex flex-col items-center py-16 text-center">
          <div className="h-14 w-14 rounded-2xl bg-amber-50 flex items-center justify-center mb-4">
            <BookOpenIcon className="h-7 w-7 text-amber-600" />
          </div>
          <h3 className="text-sm font-semibold text-slate-900">
            Content Management
          </h3>
          <p className="text-xs text-slate-500 mt-1.5 max-w-xs">
            Create, publish, and manage financial literacy courses and modules —
            coming soon.
          </p>
        </div>
      </div>
    </div>
  );
};

export default EducationPage;
