import React from "react";
import { ChartBarIcon } from "@heroicons/react/24/outline";

const AnalyticsPage = () => {
  return (
    <div className="space-y-6">
      <div>
        <h1 className="page-title">Analytics</h1>
        <p className="page-subtitle">
          Deep dive into platform analytics, reports, and business intelligence.
        </p>
      </div>

      <div className="card">
        <div className="card-body flex flex-col items-center py-16 text-center">
          <div className="h-14 w-14 rounded-2xl bg-teal-50 flex items-center justify-center mb-4">
            <ChartBarIcon className="h-7 w-7 text-teal-600" />
          </div>
          <h3 className="text-sm font-semibold text-slate-900">
            Advanced Analytics
          </h3>
          <p className="text-xs text-slate-500 mt-1.5 max-w-xs">
            Custom reports, revenue forecasting, cohort analysis, and BI
            dashboards — coming soon.
          </p>
        </div>
      </div>
    </div>
  );
};

export default AnalyticsPage;
